import pika
import subprocess
import shlex
import json
import re
import logging
import os

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ALLOWED_COMMANDS = {
    'python': '/usr/bin/python3',
    'rsync': '/usr/bin/rsync',
    'gzip': '/usr/bin/gzip',
    'tar': '/usr/bin/tar',
    'cp': '/bin/cp',
    'mv': '/bin/mv',
}

FORBIDDEN_PATTERNS = [
    r'[;&|`$]',
    r'\.\.',
    r'/etc/',
    r'/root/',
    r'rm\s',
    r'sudo',
    r'chmod',
    r'chown',
    r'curl',
    r'wget',
    r'nc\s',
    r'netcat',
    r'eval',
    r'exec',
    r'>\s*/dev/',
    r'mkfs',
    r'dd\s',
]

ALLOWED_WORKING_DIR = '/var/jobs/workspace'


def validate_command(command_str):
    """Validate and sanitize the command before execution."""
    if not isinstance(command_str, str) or not command_str.strip():
        raise ValueError("Command must be a non-empty string")

    for pattern in FORBIDDEN_PATTERNS:
        if re.search(pattern, command_str, re.IGNORECASE):
            raise ValueError(f"Command contains forbidden pattern: {pattern}")

    try:
        parts = shlex.split(command_str)
    except ValueError as e:
        raise ValueError(f"Invalid command syntax: {e}")

    if not parts:
        raise ValueError("Empty command after parsing")

    base_command = os.path.basename(parts[0])

    if base_command not in ALLOWED_COMMANDS:
        raise ValueError(f"Command '{base_command}' is not in the allowlist. Allowed: {list(ALLOWED_COMMANDS.keys())}")

    parts[0] = ALLOWED_COMMANDS[base_command]

    for arg in parts[1:]:
        if arg.startswith('-') and len(arg) > 20:
            raise ValueError(f"Suspiciously long flag: {arg}")
        resolved = os.path.realpath(arg)
        if os.path.isabs(arg) and not resolved.startswith(ALLOWED_WORKING_DIR):
            raise ValueError(f"Path argument '{arg}' is outside allowed directory")

    return parts


def validate_message(body):
    """Parse and validate the incoming message."""
    try:
        message = json.loads(body)
    except (json.JSONDecodeError, TypeError):
        raise ValueError("Message must be valid JSON")

    if not isinstance(message, dict):
        raise ValueError("Message must be a JSON object")

    if 'command' not in message:
        raise ValueError("Message must contain a 'command' field")

    job_id = message.get('job_id', 'unknown')
    command = message['command']
    timeout = message.get('timeout', 300)

    if not isinstance(timeout, (int, float)) or timeout <= 0 or timeout > 3600:
        raise ValueError("Timeout must be a positive number <= 3600")

    return job_id, command, int(timeout)


def execute_command(command_parts, timeout, job_id):
    """Execute a validated command securely using subprocess."""
    logger.info(f"Job {job_id}: Executing command: {command_parts}")

    result = subprocess.run(
        command_parts,
        shell=False,
        capture_output=True,
        text=True,
        timeout=timeout,
        cwd=ALLOWED_WORKING_DIR,
        env={
            'PATH': '/usr/bin:/bin',
            'HOME': ALLOWED_WORKING_DIR,
            'LANG': 'C.UTF-8',
        },
    )

    logger.info(f"Job {job_id}: Command exited with code {result.returncode}")
    if result.stdout:
        logger.info(f"Job {job_id}: stdout: {result.stdout[:1000]}")
    if result.stderr:
        logger.warning(f"Job {job_id}: stderr: {result.stderr[:1000]}")

    return result.returncode


def on_message(channel, method, properties, body):
    """Callback for processing messages from RabbitMQ."""
    try:
        job_id, command_str, timeout = validate_message(body)
        logger.info(f"Job {job_id}: Received command request")

        command_parts = validate_command(command_str)

        return_code = execute_command(command_parts, timeout, job_id)

        if return_code == 0:
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info(f"Job {job_id}: Completed successfully, message acknowledged")
        else:
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            logger.error(f"Job {job_id}: Failed with return code {return_code}")

    except ValueError as e:
        logger.error(f"Validation error: {e}")
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except subprocess.TimeoutExpired:
        logger.error(f"Job timed out")
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as e:
        logger.error(f"Unexpected error processing message: {e}")
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)


def main():
    credentials = pika.PlainCredentials(
        os.environ.get('RABBITMQ_USER', 'guest'),
        os.environ.get('RABBITMQ_PASS', 'guest'),
    )

    ssl_options = None
    rabbitmq_host = os.environ.get('RABBITMQ_HOST', 'localhost')
    rabbitmq_port = int(os.environ.get('RABBITMQ_PORT', 5672))

    connection_params = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        credentials=credentials,
        ssl_options=ssl_options,
    )

    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()

    queue_name = os.environ.get('JOB_QUEUE', 'job_queue')
    channel.queue_declare(queue=queue_name, durable=True)
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=queue_name, on_message_callback=on_message)

    logger.info(f"Waiting for job messages on queue '{queue_name}'. Press CTRL+C to exit.")

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down consumer...")
        channel.stop_consuming()
    finally:
        connection.close()


